import time
from typing import List

def batch_embed_with_retry(
    texts: List[str],
    batch_size: int = 100,
    max_retries: int = 3
) -> List[List[float]]:
    """Batch embed with retry logic"""
    all_vectors = []
    
    for i in range(0, len(texts), batch_size):
        batch = texts[i:i+batch_size]
        
        for attempt in range(max_retries):
            try:
                vectors = embeddings.embed_documents(batch)
                all_vectors.extend(vectors)
                break
            except Exception as e:
                if attempt == max_retries - 1:
                    raise
                wait_time = 2 ** attempt  # Exponential backoff
                print(f"Retry {attempt + 1} after {wait_time}s: {e}")
                time.sleep(wait_time)
    
    return all_vectors

        
# Production-optimized HNSW configuration
index_params = {
    "metric_type": "COSINE",
    "index_type": "HNSW",
    "params": {
        "M": 32,              # Higher for better recall
        "efConstruction": 512  # Higher for better index quality
    }
}

# Search with optimized ef
search_params = {
    "metric_type": "COSINE",
    "params": {
        "ef": 200  # Higher for better recall
    }
}

