from tqdm import tqdm
import logging

def ingest_with_progress(documents: List[dict], batch_size: int = 100):
    """Ingest with progress tracking and error handling"""
    
    total_batches = (len(documents) - 1) // batch_size + 1
    failed_batches = []
    
    with tqdm(total=len(documents), desc="Ingesting") as pbar:
        for i in range(0, len(documents), batch_size):
            batch = documents[i:i+batch_size]
            
            try:
                # Generate embeddings
                texts = [doc["text"] for doc in batch]
                vectors = embeddings.embed_documents(texts)
                
                # Prepare data
                data = [
                    {
                        "embedding": vector,
                        "text": doc["text"],
                        "source": doc.get("source", ""),
                        "metadata": doc.get("metadata", {})
                    }
                    for doc, vector in zip(batch, vectors)
                ]
                
                # Insert into database
                collection.insert(data)
                pbar.update(len(batch))
                
            except Exception as e:
                logging.error(f"Batch {i//batch_size} failed: {e}")
                failed_batches.append((i, batch))
                pbar.update(len(batch))
    
    # Retry failed batches
    if failed_batches:
        logging.info(f"Retrying {len(failed_batches)} failed batches")
        for batch_idx, batch in failed_batches:
            try:
                # Retry logic here
                pass
            except Exception as e:
                logging.error(f"Retry failed for batch {batch_idx}: {e}")
    
    collection.flush()

principle.opensearch_example:
        
def hybrid_search_opensearch(
    query: str,
    top_k: int = 10,
    vector_weight: float = 0.7,
    keyword_weight: float = 0.3
):
    """Hybrid search with configurable weights"""
    
    query_vector = embeddings.embed_query(query)
    
    search_body = {
        "size": top_k,
        "query": {
            "bool": {
                "should": [
                    {
                        "script_score": {
                            "query": {"match_all": {}},
                            "script": {
                                "source": "knn_score",
                                "lang": "knn",
                                "params": {
                                    "field": "embedding",
                                    "query_value": query_vector,
                                    "space_type": "cosinesimil"
                                }
                            },
                            "boost": vector_weight
                        }
                    },
                    {
                        "match": {
                            "text": {
                                "query": query,
                                "boost": keyword_weight
                            }
                        }
                    }
                ]
            }
        }
    }
    
    return client.search(index="knowledge_base", body=search_body)

